import React, { useState, useEffect } from "react";
import Academypopup from "../../components/Users/Acknowledgement/Academypopup";

import { useNavigate } from 'react-router-dom';
import SideBar from '../../components/Investor/social/SideBar';
import TopBar from '../../components/Investor/social/TopBar';
import {
    SectionWrapper,
    Wrapper,
} from "../../components/Styles/RegisterStyles";
import EducationData from "../../components/EducationDataCompany";
export default function InvestorEducation() {
    const [activeTab, setActiveTab] = useState("founders");
    const [PopupShow, setPopupShow] = useState(false);
    const investorData = localStorage.getItem("InvestorData");
    const signatoryData = localStorage.getItem("SignatoryLoginData");
    const navigate = useNavigate();
    let userLogin = null;
    console.log(investorData, signatoryData)
    if (investorData) {
        userLogin = JSON.parse(investorData);
    } else if (signatoryData) {
        userLogin = JSON.parse(signatoryData);
    }

    // If both are null, navigate to login
    useEffect(() => {

        if (!userLogin) {
            navigate('/user/login');
        }
    }, [userLogin, navigate]);
    // Handle hash navigation from other pages
    useEffect(() => {
        // Check if there's a hash in the URL
        if (window.location.hash) {
            const hash = window.location.hash.substring(1); // Remove the # symbol

            // Wait a bit for the DOM to fully render
            setTimeout(() => {
                scrollToSection(hash);
            }, 500);
        }
    }, []);

    // Function to scroll to section
    const scrollToSection = (sectionId) => {
        const element = document.getElementById(sectionId);
        if (element) {
            const offset = 80; // Adjust for fixed header height
            const elementPosition = element.getBoundingClientRect().top;
            const offsetPosition = elementPosition + window.pageYOffset - offset;

            window.scrollTo({
                top: offsetPosition,
                behavior: "smooth"
            });
        }
    };

    // Listen for hash changes
    useEffect(() => {
        const handleHashChange = () => {
            if (window.location.hash) {
                const hash = window.location.hash.substring(1);
                setTimeout(() => {
                    scrollToSection(hash);
                }, 100);
            }
        };

        window.addEventListener('hashchange', handleHashChange);
        return () => window.removeEventListener('hashchange', handleHashChange);
    }, []);
    const handleAcademyPopup = () => {
        setPopupShow(true)
    }
    const handleClosePopup = () => {
        setPopupShow(false);
    };
    return (
        <>

            <main>
                <div className='d-flex align-items-start gap-0'>
                    <SideBar />
                    <div className='d-flex flex-grow-1 flex-column gap-0'>
                        <TopBar />
                        <SectionWrapper className="d-block p-md-4 p-3">
                            <div className="container-fluid">
                                <EducationData section={false} />
                            </div>
                        </SectionWrapper>
                    </div>
                </div>
            </main>
        </>
    );
}
